import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { useSocket } from '../../contexts/SocketContext';
import axios from 'axios';
import './AdminPages.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const AdminMessages = () => {
  const { user } = useAuth();
  const { socket } = useSocket();
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedMessage, setSelectedMessage] = useState(null);
  const [replyText, setReplyText] = useState('');
  const [sendingReply, setSendingReply] = useState(false);
  const [notification, setNotification] = useState(null);
  const [unreadCount, setUnreadCount] = useState(0);
  const [filter, setFilter] = useState('all'); // all, unread, replied
  const [pagination, setPagination] = useState({
    page: 1,
    total: 0,
    pages: 1
  });

  useEffect(() => {
    fetchMessages();
    fetchUnreadCount();

    // Listen for new messages
    if (socket) {
      socket.on('new_message_notification', (data) => {
        setNotification({
          type: 'new',
          message: `New message from ${data.user.name}: ${data.subject}`,
          data
        });
        fetchMessages();
        fetchUnreadCount();
        
        // Play sound notification
        const audio = new Audio('/notification.mp3');
        audio.play().catch(() => {});
        
        // Show browser notification
        if (Notification.permission === 'granted') {
          new Notification('New Support Message', {
            body: `From: ${data.user.name}\nSubject: ${data.subject}`,
            icon: '/logo192.png'
          });
        }
      });

      return () => {
        socket.off('new_message_notification');
      };
    }

    // Request notification permission
    if (Notification.permission === 'default') {
      Notification.requestPermission();
    }
  }, [socket]);

  useEffect(() => {
    if (notification) {
      const timer = setTimeout(() => setNotification(null), 5000);
      return () => clearTimeout(timer);
    }
  }, [notification]);

  const fetchMessages = async () => {
    try {
      const response = await axios.get(`${API_URL}/messages/admin/all`, {
        params: {
          status: filter !== 'all' ? filter : undefined,
          page: pagination.page
        }
      });
      setMessages(response.data.data || []);
      setPagination(response.data.pagination);
    } catch (error) {
      console.error('Error fetching messages:', error);
    } finally {
      setLoading(false);
    }
  };

  const fetchUnreadCount = async () => {
    try {
      const response = await axios.get(`${API_URL}/messages/admin/unread-count`);
      setUnreadCount(response.data.count || 0);
    } catch (error) {
      console.error('Error fetching unread count:', error);
    }
  };

  const handleReply = async (messageId) => {
    if (!replyText.trim()) return;
    
    setSendingReply(true);
    try {
      await axios.post(`${API_URL}/messages/${messageId}/reply`, {
        reply: replyText
      });
      
      setSelectedMessage(null);
      setReplyText('');
      fetchMessages();
      
      setNotification({
        type: 'success',
        message: 'Reply sent successfully'
      });
    } catch (error) {
      console.error('Error sending reply:', error);
      setNotification({
        type: 'error',
        message: 'Failed to send reply'
      });
    } finally {
      setSendingReply(false);
    }
  };

  const markAsRead = async (messageId) => {
    try {
      await axios.put(`${API_URL}/messages/${messageId}/read`);
      fetchUnreadCount();
    } catch (error) {
      console.error('Error marking as read:', error);
    }
  };

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    return date.toLocaleString('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  return (
    <div className="admin-page-container">
      {/* Notification Toast */}
      {notification && (
        <div className={`notification-toast ${notification.type}`}>
          <span className="notification-icon">
            {notification.type === 'new' ? '💬' : 
             notification.type === 'success' ? '✅' : '❌'}
          </span>
          <span className="notification-message">{notification.message}</span>
          <button className="notification-close" onClick={() => setNotification(null)}>×</button>
        </div>
      )}

      {/* Page Header */}
      <div className="page-header">
        <div>
          <h1 className="page-title">Support Messages</h1>
          <p className="page-description">
            Manage customer inquiries and support requests
            {unreadCount > 0 && (
              <span className="unread-badge">
                {unreadCount} unread
              </span>
            )}
          </p>
        </div>
        <div className="filter-controls">
          <select 
            value={filter} 
            onChange={(e) => setFilter(e.target.value)}
            className="filter-select"
          >
            <option value="all">All Messages</option>
            <option value="unread">Unread Only</option>
            <option value="replied">Replied</option>
          </select>
        </div>
      </div>

      {/* Messages Grid */}
      {loading ? (
        <div className="loading-state">Loading messages...</div>
      ) : messages.length === 0 ? (
        <div className="empty-state">
          <div className="empty-icon">📭</div>
          <h3>No Messages Found</h3>
          <p>There are no support messages to display.</p>
        </div>
      ) : (
        <div className="messages-grid">
          {messages.map((message) => (
            <div 
              key={message._id} 
              className={`message-card ${!message.isAdminRead ? 'unread' : ''}`}
              onClick={() => {
                setSelectedMessage(message);
                if (!message.isAdminRead) {
                  markAsRead(message._id);
                }
              }}
            >
              <div className="message-card-header">
                <div className="customer-info">
                  <span className="customer-name">
                    {message.user?.firstName} {message.user?.lastName}
                  </span>
                  <span className="customer-email">{message.user?.email}</span>
                </div>
                <span className={`message-status ${message.status}`}>
                  {message.status}
                </span>
              </div>
              
              <div className="message-card-body">
                <h4 className="message-subject">{message.subject}</h4>
                <p className="message-preview">
                  {message.message.substring(0, 100)}
                  {message.message.length > 100 && '...'}
                </p>
              </div>
              
              <div className="message-card-footer">
                <span className="message-date">{formatDate(message.createdAt)}</span>
                {message.status === 'replied' && (
                  <span className="replied-badge">Replied</span>
                )}
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Pagination */}
      {pagination.pages > 1 && (
        <div className="pagination">
          <button 
            onClick={() => setPagination({ ...pagination, page: pagination.page - 1 })}
            disabled={pagination.page === 1}
            className="pagination-btn"
          >
            Previous
          </button>
          <span className="page-info">
            Page {pagination.page} of {pagination.pages}
          </span>
          <button 
            onClick={() => setPagination({ ...pagination, page: pagination.page + 1 })}
            disabled={pagination.page === pagination.pages}
            className="pagination-btn"
          >
            Next
          </button>
        </div>
      )}

      {/* Reply Modal */}
      {selectedMessage && (
        <div className="modal-overlay" onClick={() => setSelectedMessage(null)}>
          <div className="modal-container" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h2>Reply to Message</h2>
              <button className="modal-close" onClick={() => setSelectedMessage(null)}>×</button>
            </div>
            
            <div className="modal-body">
              <div className="customer-details">
                <h4>From: {selectedMessage.user?.firstName} {selectedMessage.user?.lastName}</h4>
                <p className="customer-email">{selectedMessage.user?.email}</p>
                <p className="customer-phone">{selectedMessage.user?.phone || 'No phone'}</p>
              </div>
              
              <div className="original-message">
                <h4>Subject: {selectedMessage.subject}</h4>
                <p className="message-content">{selectedMessage.message}</p>
                <small>Received: {formatDate(selectedMessage.createdAt)}</small>
              </div>

              {selectedMessage.adminReply && (
                <div className="previous-reply">
                  <h4>Previous Reply:</h4>
                  <p>{selectedMessage.adminReply}</p>
                  <small>{formatDate(selectedMessage.repliedAt)}</small>
                </div>
              )}

              <div className="reply-form">
                <label className="form-label">Your Reply</label>
                <textarea
                  value={replyText}
                  onChange={(e) => setReplyText(e.target.value)}
                  rows="5"
                  className="form-textarea"
                  placeholder="Type your reply here..."
                  maxLength="2000"
                />
                <small className="char-count">{replyText.length}/2000</small>
              </div>
            </div>
            
            <div className="modal-footer">
              <button 
                className="btn-secondary" 
                onClick={() => setSelectedMessage(null)}
              >
                Cancel
              </button>
              <button 
                className="btn-primary" 
                onClick={() => handleReply(selectedMessage._id)}
                disabled={!replyText.trim() || sendingReply}
              >
                {sendingReply ? 'Sending...' : 'Send Reply'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminMessages;
